mapper.select:
SELECT * FROM website_access_log
WHERE access_time BETWEEN #{startDate} AND #{endDate}
ORDER BY access_time DESC

SELECT COUNT(DISTINCT page_url)
FROM website_access_log
WHERE access_time BETWEEN #{startDate} AND #{endDate}

SELECT CASE WHEN referer IS NULL OR referer = '' THEN 'direct' WHEN referer LIKE '%google%' OR referer LIKE '%bing%' OR referer LIKE '%baidu%' OR referer LIKE '%yahoo%' THEN 'search' WHEN referer LIKE '%weibo%' OR referer LIKE '%wechat%' OR referer LIKE '%twitter%' OR referer LIKE '%facebook%' OR referer LIKE '%zhihu%' THEN 'social' ELSE 'referral' END AS source_type, COALESCE(referer, '直接访问') AS source_name, COUNT(*) AS visit_count, COUNT(DISTINCT ip_address) AS unique_visitor FROM website_access_log
AND access_date >= #{startDate}
AND access_date <= #{endDate}
GROUP BY source_type, source_name ORDER BY visit_count DESC
LIMIT #{limit}

SELECT page_url, COUNT(*) AS visit_count, COUNT(DISTINCT ip_address) AS unique_visitor FROM website_access_log WHERE page_url IS NOT NULL AND page_url != ''
AND access_date >= #{startDate}
AND access_date <= #{endDate}
GROUP BY page_url ORDER BY visit_count DESC LIMIT #{offset}, #{size}
